SELECT AVG(pillar_score) AS average_pillar_score
FROM pillar_scores
WHERE year = '2022';

SELECT pillar_score
FROM pillar_scores
WHERE pillar_name = 'Access' AND year = '2022';

SELECT COUNT(service_id) AS service_count
FROM rehabilitation_services
WHERE service_name = 'Inpatient';

SELECT AVG(cost) AS average_cost
FROM early_rehab_services
WHERE target_age_group = '0-5 years';

SELECT target_age_group, AVG(cost) AS average_cost
FROM early_rehab_services
GROUP BY target_age_group;

SELECT description
FROM early_rehab_services
WHERE end_date >= '2023-12-31';

SELECT AVG(score) AS average_score
FROM rehabilitation_services
WHERE country_id = 0;

SELECT MAX(pillar_score) AS highest_access_score
FROM pillar_scores
WHERE country_id = 0 AND pillar_name = 'Access';

SELECT AVG(cost) AS average_cost
FROM outpatient_rehab_services
WHERE country_id = 0;

SELECT country_id, pillar_name, MAX(pillar_score) AS max_pillar_score, year
FROM pillar_scores
GROUP BY country_id, pillar_name, year;

SELECT service_name, AVG(score) AS average_score
FROM rehabilitation_services
GROUP BY service_name;

SELECT AVG(pillar_score) AS average_quality_score
FROM pillar_scores
WHERE pillar_name = 'Quality';
